# ============================================================
# 工具函数 (对应 pipeline/utils.py)
# ============================================================
def to_str(v):
    if v is None: return ''
    s = str(v).strip()
    return '' if s in ('nan','NaT','None','NaN','nat','') else s

def to_num(v):
    try: return float(to_str(v))
    except (ValueError, TypeError): return 0.0

def parse_hm(s):
    s = to_str(s)
    if not s: return None
    if ' ' in s or '-' in s:
        parts = s.replace('1900-01-01 ','').strip().split(':')
    else:
        parts = s.split(':')
    try: return timedelta(hours=int(parts[0]), minutes=int(parts[1]))
    except: return None

def abs_diff_minutes(t1, t2):
    p1, p2 = parse_hm(t1), parse_hm(t2)
    if p1 is None or p2 is None: return None
    return abs((p1 - p2).total_seconds() / 60)

def total_hours(hms_str):
    s = to_str(hms_str)
    if s == '': return 0.0
    try: return round(float(s)*24, 2)
    except: pass
    try:
        parts = s.split(':')
        return int(parts[0]) + int(parts[1])/60
    except: return 0.0

def parse_date(s):
    for fmt in ['%Y-%m-%d %H:%M:%S','%Y/%m/%d','%Y-%m-%d','%m/%d/%Y']:
        try: return pd.to_datetime(s, format=fmt)
        except: pass
    try: return pd.to_datetime(s)
    except: return pd.NaT

def parse_work_period(s):
    s = to_str(s)
    if not s: return None
    m = re.search(r'(?:居家办公|公出|出差|病假|年假|无薪病假).*?(\d{1,2}:\d{2})-.*?(\d{1,2}:\d{2})', s)
    if m:
        sh,sm = int(m.group(1).split(':')[0]), int(m.group(1).split(':')[1])
        eh,em = int(m.group(2).split(':')[0]), int(m.group(2).split(':')[1])
        return timedelta(hours=sh,minutes=sm), timedelta(hours=eh,minutes=em)
    return None

def safe_div(a, b): return round(a/b,4) if b else 0.0
def pct_str(v): return f"{round(v*100,1)}%"

# ============================================================
# 业务常量
# ============================================================
GL00_WHITELIST = {'GL000434','GL001344','GL000004','GL000440','GL000446','GL000902','GL001183'}
GL00_EXTRA_REMOVE = {'GL502563'}

# ============================================================
# 步骤1: 数据清洗 (对应 pipeline/steps/clean_data.py)
# ============================================================
def run_clean(config, roster_index=12):
    raw_path    = config['raw_file']
    leave_path  = config['leave_file']
    roster_path = config['roster_pattern'].format(n=roster_index)
    output_file = config['cleaned_file']

    df_raw = pd.read_excel(raw_path, header=0, dtype=str)
    if str(df_raw.iloc[0].get('考勤日期','')).strip() == '考勤日期':
        df_raw = df_raw.iloc[1:].reset_index(drop=True)
    print(f"原始数据行数: {len(df_raw)}")

    # 识别标准日期
    date_col = '考勤日期'
    df_raw[date_col] = df_raw[date_col].astype(str).str.strip()
    non_empty = df_raw[df_raw[date_col].notna() & ~df_raw[date_col].isin(['','nan','NaT'])]
    parsed = non_empty[date_col].apply(parse_date).dropna().unique()
    standard_dates = sorted([d for d in parsed if pd.notna(d)])
    standard_date = max(standard_dates) if len(standard_dates)>1 else standard_dates[0]
    print(f"标准日期: {standard_date.date()}")

    # 步骤1: 剔除离职
    if os.path.exists(leave_path):
        df_leave = pd.read_excel(leave_path, header=0, dtype=str)
        df_leave['_lwd'] = df_leave['最后工作日'].apply(parse_date)
        has_status = df_leave['审批状态'].notna().any() and df_leave['审批状态'].apply(lambda x: to_str(x) not in ['','nan','None']).any()
        if has_status:
            leave_filter = ['审批中','已完成','转交']
            df_leave['_sv'] = df_leave['审批状态'].apply(lambda x: any(s in str(x) for s in leave_filter) if pd.notna(x) else False)
            leave_ids = set(df_leave[(df_leave['_lwd']<standard_date)&(df_leave['_sv'])]['工号'].dropna().unique())
        else:
            leave_ids = set(df_leave[df_leave['_lwd']<standard_date]['工号'].dropna().unique())
        before = len(df_raw)
        df_raw = df_raw[~df_raw['工号'].isin(leave_ids)]
        print(f"步骤1-离职剔除: {before}→{len(df_raw)} ({len(leave_ids)}个工号)")

    # 步骤2: 剔除未入职
    if os.path.exists(roster_path):
        df_roster = pd.read_excel(roster_path, header=0, dtype=str)
        df_roster['_jd'] = df_roster['入职日期'].apply(parse_date)
        not_joined = set(df_roster[df_roster['_jd']>standard_date]['工号'].dropna().unique())
        before = len(df_raw)
        df_raw = df_raw[~df_raw['工号'].isin(not_joined)]
        print(f"步骤2-未入职剔除: {before}→{len(df_raw)} ({len(not_joined)}个工号)")

    # 步骤3: GL00
    before = len(df_raw)
    df_raw = df_raw[~df_raw['工号'].isin(GL00_EXTRA_REMOVE)]
    is_gl00 = df_raw['工号'].str.startswith('GL00', na=False)
    not_wl = ~df_raw['工号'].isin(GL00_WHITELIST)
    df_raw = df_raw[~(is_gl00 & not_wl)]
    print(f"步骤3-GL00处理: {before}→{len(df_raw)}")

    # 步骤4: EU人力资源部
    before = len(df_raw)
    df_raw = df_raw[df_raw['三级部门'].str.strip()!='EU人力资源部']
    print(f"步骤4-EU剔除: {before}→{len(df_raw)}")

    # 步骤5: 补签数
    resign_path = config['resign_file']
    if os.path.exists(resign_path):
        df_resign = pd.read_excel(resign_path, header=0, dtype=str)
        df_resign = df_resign[df_resign['审批状态'].apply(lambda x: to_str(x) in ['已完成','审批中','转交'] if pd.notna(x) else False)]
        df_resign['_rd'] = df_resign['补签日期'].apply(parse_date)
        df_resign = df_resign[df_resign['_rd']==standard_date]
        resign_counts = df_resign.groupby('工号').size().reset_index(name='补签数')
        df_raw = df_raw.merge(resign_counts, on='工号', how='left')
        df_raw['补签数'] = df_raw['补签数'].fillna(0).astype(int)
    else:
        df_raw['补签数'] = 0

    # 步骤6: 签字报表
    for key, col_name, sub40 in [
        ('sign_report_this_week','本周累计加班工时',True),
        ('sign_report_last_week','上周累计加班工时',True),
        ('sign_report_biweek','双周累计工时',False)]:
        sp = config[key]
        if os.path.exists(sp):
            df_s = pd.read_excel(sp, header=0, dtype=str)
            acc = {}
            for _, r in df_s.iterrows():
                eid = to_str(r.get('工号',''))
                hrs = sum(total_hours(v) for v in r.values)
                acc[eid] = acc.get(eid,0) + hrs
            if sub40:
                for k in acc: acc[k] = max(0, acc[k]-40)
            tmp = pd.DataFrame(list(acc.items()), columns=['工号',col_name])
            df_raw = df_raw.merge(tmp, on='工号', how='left')
            df_raw[col_name] = df_raw[col_name].fillna(0)
        else:
            df_raw[col_name] = 0

    df_raw.to_excel(output_file, index=False)
    print(f"清洗完成: {output_file} ({len(df_raw)}行)")
    return df_raw

# ============================================================
# 步骤2: 指标计算 (对应 pipeline/steps/add_metrics.py)
# ============================================================
def get_hub(row):
    d4, d5 = to_str(row.get('四级部门','')), to_str(row.get('五级部门',''))
    return 'hub' if ('.H' in d5 or '.H' in d4 or d5=='EWR.G' or d5=='CNO.G') else ''

def get_correct(row):
    first, last = to_str(row.get('首打卡时间','')), to_str(row.get('末打卡时间',''))
    shift = to_str(row.get('班次名称',''))
    start_t, end_t = to_str(row.get('班次上班时间','')), to_str(row.get('班次下班时间',''))
    if not shift: return '/'
    is_rest = 'TY_休息日' in shift or 'TY_美国节假日' in shift
    if is_rest and not first and not last: return '正确'
    if not is_rest and not first:
        d = abs_diff_minutes(last, end_t)
        return '正确' if (d is not None and d<=60) else '不正确'
    if not last:
        d = abs_diff_minutes(first, start_t)
        return '正确' if (d is not None and d<=60) else '不正确'
    if is_rest:
        if (not first and last) or (first and not last): return '不正确'
    if not is_rest and first and last:
        d = abs_diff_minutes(first, start_t)
        return '正确' if (d is not None and d<=60) else '不正确'
    return '不正确'

def get_daily_total(row, daily_col=None):
    if daily_col is None:
        for c in ['每日总工时(公式：末打卡-首打卡-班次午休时间+居家办公时长)合计',
                  '每日总工时(公式：末打卡时间-首打卡时间-班次午休时间+居家办公时长)合计',
                  '每日总工时(公式：末打卡时间-首打卡时间-班次午休时间+居家办公时长)']:
            if c in row.index: daily_col = c; break
    base = to_num(row.get(daily_col,0)) if daily_col else 0.0
    ho = to_num(row.get('居家办公合计（审批中）',0))
    return round(base+ho, 2)

def get_over8h(row):
    return '是' if to_num(row.get('日超8H',0))!=0 else '否'

def get_standard_count(row, is_correct, shift_name, note):
    is_scheduled = bool(to_str(shift_name))
    is_rest = 'TY_休息日' in to_str(shift_name) or 'TY_美国节假日' in to_str(shift_name)
    if not is_scheduled: return 4
    if is_rest: return 0
    if not to_str(note): return 4
    period = parse_work_period(to_str(note))
    if period is None: return 4
    ps, pe = period
    ss = parse_hm(to_str(row.get('班次上班时间','')))
    se = parse_hm(to_str(row.get('班次下班时间','')))
    rs = parse_hm(to_str(row.get('休息开始时间','')))
    re_ = parse_hm(to_str(row.get('休息结束时间','')))
    if ss is None or se is None: return 4
    ph = (pe-ps).total_seconds()/3600
    if ps==ss and pe==se: return 0
    if is_correct=='正确':
        if rs is not None and re_ is not None:
            if ps>=rs and pe<=re_: return 0
            if (ps<re_ and pe>rs and not(ps<=rs and pe>=re_) and ps>=ss and pe<=se): return 3
            if (ps<=rs and pe>=re_ and ps>=ss and pe<=se): return 2
            return 4
        return 4
    else:
        if ph>=7: return 0
        if ph>=4: return 2
        return 4

def run_metrics(config):
    df = pd.read_excel(config['cleaned_file'], dtype=str)
    print(f"清洗后数据: {len(df)}行")

    # 班次字典
    shift_dict = {}
    if os.path.exists(config['shift_file']):
        sdf = pd.read_excel(config['shift_file'], dtype=str)
        for _, r in sdf.iterrows():
            n = to_str(r.get('班次名称',''))
            if n: shift_dict[n] = {'rs':to_str(r.get('休息开始时间','')),'re':to_str(r.get('休息结束时间',''))}

    # 每日总工时列名
    daily_col = None
    for c in ['每日总工时(公式：末打卡-首打卡-班次午休时间+居家办公时长)合计',
              '每日总工时(公式：末打卡时间-首打卡时间-班次午休时间+居家办公时长)合计',
              '每日总工时(公式：末打卡时间-首打卡时间-班次午休时间+居家办公时长)']:
        if c in df.columns: daily_col = c; break

    records = []
    for _, row in df.iterrows():
        r = row.to_dict()
        sn = to_str(r.get('班次名称',''))
        note = to_str(r.get('备注（GF）',''))
        sd = shift_dict.get(sn, {})
        r['休息开始时间'] = sd.get('rs','')
        r['休息结束时间'] = sd.get('re','')
        r['HUB'] = get_hub(r)
        r['是否排班正确'] = get_correct(row)
        r['每日总工时计算'] = get_daily_total(row, daily_col)
        r['是否日超8H'] = get_over8h(row)
        r['是否排班'] = '是' if sn else '否'
        r['标准打卡数'] = get_standard_count(row, r['是否排班正确'], sn, note)
        r['缺卡数'] = max(0.0, r['标准打卡数']-to_num(r.get('班次内打卡次数',0)))
        records.append(r)

    out = pd.DataFrame(records)
    out.to_excel(config['metrics_file'], index=False)
    print(f"指标计算完成: {config['metrics_file']}")
    for col in ['是否排班正确','是否日超8H','是否排班','HUB']:
        if col in out.columns: print(f"  {col}: {out[col].value_counts().to_dict()}")

# ============================================================
# 步骤3: 透视分析 (对应 pipeline/steps/pivot_analysis.py)
# ============================================================
from openpyxl import Workbook
from openpyxl.styles import PatternFill, Font, Alignment, Border, Side
from openpyxl.utils import get_column_letter

HEADER_FILL=PatternFill("solid",fgColor="4472C4")
HEADER_FONT=Font(color="FFFFFF",bold=True,name="微软雅黑",size=11)
SUMMARY_FILL=PatternFill("solid",fgColor="E2EFDA")
SUMMARY_FONT=Font(bold=True,name="微软雅黑",size=11)
DATA_FONT=Font(name="微软雅黑",size=11)
CENTER=Alignment(horizontal="center",vertical="center",wrap_text=False)
THIN=Side(style='thin',color='CCCCCC')
BORDER=Border(left=THIN,right=THIN,top=THIN,bottom=THIN)
PCT_FMT='0.00%'

def _sc(cell, is_sum, nf=None):
    cell.font=SUMMARY_FONT if is_sum else DATA_FONT; cell.alignment=CENTER; cell.border=BORDER
    if is_sum: cell.fill=SUMMARY_FILL
    if nf: cell.number_format=nf

def _ws(ws, ch, rows_data, rate_cols=None):
    for j,cn in ch: c=ws.cell(1,j,cn); c.fill=HEADER_FILL; c.font=HEADER_FONT; c.alignment=CENTER; c.border=BORDER
    for i,row in enumerate(rows_data,2):
        is_sum=row.get('_is_summary',False)
        for j,cn in ch: _sc(ws.cell(i,j,row.get(cn,'')), is_sum)
        if rate_cols:
            for pc,nk,dk in rate_cols:
                num=float(row.get(nk,0)or 0); denom=float(row.get(dk,0)or 0)
                rate=num/denom if denom else None
                _sc(ws.cell(i,pc,rate), is_sum, PCT_FMT)
    for col in ws.columns:
        ml=max((len(str(c.value)) if c.value is not None else 0) for c in col)
        ws.column_dimensions[get_column_letter(col[0].column)].width=min(max(ml+4,10),32)
    ws.freeze_panes='A2'

def run_pivot(config):
    df=pd.read_excel(config['metrics_file'], dtype=str)
    print(f"透视分析数据: {len(df)}行")
    df['_o8n']=(df['是否日超8H']=='是').astype(int)
    df['_psn']=(df['是否排班']=='是').astype(int)
    df['_pn']=(df['是否排班正确']=='正确').astype(int)
    df['_inn']=(df['是否排班正确']=='不正确').astype(int)
    df['_mss']=df['缺卡数'].apply(to_num)
    df['_std']=df['标准打卡数'].apply(to_num)
    df['_pch']=df['班次内打卡次数'].apply(to_num)
    df['_o8h']=df['日超8H'].apply(to_num)
    df['_bq']=df['补签数'].apply(to_num)

    rows_list=[]
    for d3,grp in df.groupby('三级部门'):
        d3v=to_str(d3)
        gne=grp[grp['四级部门'].apply(lambda x:to_str(x)!='')]
        ge=grp[grp['四级部门'].apply(lambda x:to_str(x)=='')]
        for d4,sub in gne.groupby('四级部门'):
            su=sub.drop_duplicates(subset=['工号'])
            cnt=len(su)
            over=int(sub['_o8n'].sum()); over_h=round(sub['_o8h'].sum(),2)
            shift=int(sub['_psn'].sum()); corr=int(sub['_pn'].sum()); incorr=int(sub['_inn'].sum())
            miss=round(sub['_mss'].sum(),2); std=round(sub['_std'].sum(),2); punch=round(sub['_pch'].sum(),2)
            ea=sub.groupby('工号').agg(bq=('补签数','first'),qk=('缺卡数',lambda x:x.apply(to_num).sum()))
            bqe=ea['bq'].apply(to_num).sum(); qke=ea['qk'].sum()
            rows_list.append({'三级部门':d3v,'四级部门':to_str(d4),'计数':cnt,'超过人数':over,'超过小时合计':over_h,'未超过人数':cnt-over,'已排班数':shift,'未排班数':cnt-shift,'正确数量':corr,'不正确数量':incorr,'总计人数':corr+incorr,'缺卡数量':miss,'标准打卡数量':std,'打卡数':punch,'补签数_emp':bqe,'缺卡数_emp':qke,'_is_summary':False})
        if len(ge)>0:
            cnt=len(ge.drop_duplicates(subset=['工号']))
            over=int(ge['_o8n'].sum()); over_h=round(ge['_o8h'].sum(),2)
            shift=int(ge['_psn'].sum()); corr=int(ge['_pn'].sum()); incorr=int(ge['_inn'].sum())
            miss=round(ge['_mss'].sum(),2); std=round(ge['_std'].sum(),2); punch=round(ge['_pch'].sum(),2)
            ea=ge.groupby('工号').agg(bq=('补签数','first'),qk=('缺卡数',lambda x:x.apply(to_num).sum()))
            bqe=ea['bq'].apply(to_num).sum(); qke=ea['qk'].sum()
            rows_list.append({'三级部门':d3v,'四级部门':'/','计数':cnt,'超过人数':over,'超过小时合计':over_h,'未超过人数':cnt-over,'已排班数':shift,'未排班数':cnt-shift,'正确数量':corr,'不正确数量':incorr,'总计人数':corr+incorr,'缺卡数量':miss,'标准打卡数量':std,'打卡数':punch,'补签数_emp':bqe,'缺卡数_emp':qke,'_is_summary':False})
        cnt=len(grp.drop_duplicates(subset=['工号']))
        over=int(grp['_o8n'].sum()); over_h=round(grp['_o8h'].sum(),2)
        shift=int(grp['_psn'].sum()); corr=int(grp['_pn'].sum()); incorr=int(grp['_inn'].sum())
        miss=round(grp['_mss'].sum(),2); std=round(grp['_std'].sum(),2); punch=round(grp['_pch'].sum(),2)
        ea=grp.groupby('工号').agg(bq=('补签数','first'),qk=('缺卡数',lambda x:x.apply(to_num).sum()))
        bqe=ea['bq'].apply(to_num).sum(); qke=ea['qk'].sum()
        rows_list.append({'三级部门':d3v,'四级部门':'汇总','计数':cnt,'超过人数':over,'超过小时合计':over_h,'未超过人数':cnt-over,'已排班数':shift,'未排班数':cnt-shift,'正确数量':corr,'不正确数量':incorr,'总计人数':corr+incorr,'缺卡数量':miss,'标准打卡数量':std,'打卡数':punch,'补签数_emp':bqe,'缺卡数_emp':qke,'_is_summary':True})

    pv=pd.DataFrame(rows_list); pv['_补签率分母']=pv['补签数_emp']+pv['缺卡数_emp']
    wb=Workbook(); wb.remove(wb.active)
    ws1=wb.create_sheet("日超8H"); _ws(ws1,[(1,'三级部门'),(2,'四级部门'),(3,'超过小时合计'),(4,'总计人数')],pv.to_dict('records'))
    ws2=wb.create_sheet("是否排班"); _ws(ws2,[(1,'三级部门'),(2,'四级部门'),(3,'已排班数'),(4,'未排班数'),(5,'总计人数'),(6,'排班率')],pv.to_dict('records'),rate_cols=[(6,'已排班数','计数')])
    ws3=wb.create_sheet("是否排班正确"); _ws(ws3,[(1,'三级部门'),(2,'四级部门'),(3,'正确数量'),(4,'不正确数量'),(5,'总计人数'),(6,'正确率')],pv.to_dict('records'),rate_cols=[(6,'正确数量','计数')])
    ws4=wb.create_sheet("打卡率"); _ws(ws4,[(1,'三级部门'),(2,'四级部门'),(3,'打卡数'),(4,'标准打卡数量'),(5,'打卡率'),(6,'缺卡数'),(7,'补签数(唯一工号)'),(8,'补签率')],pv.to_dict('records'),rate_cols=[(5,'打卡数','标准打卡数量'),(8,'补签数_emp','_补签率分母')])

    # HUB Sheet
    dfh=df[df['HUB'].apply(lambda x:to_str(x)=='hub')].copy()
    hr=[]
    for d3,grp in dfh.groupby('三级部门'):
        d3v=to_str(d3)
        gne=grp[grp['五级部门'].apply(lambda x:to_str(x)!='')]; ge=grp[grp['五级部门'].apply(lambda x:to_str(x)=='')]
        for d5,sub in gne.groupby('五级部门'):
            su=sub.drop_duplicates(subset=['工号']); cnt=len(su)
            corr=int(sub['_pn'].sum()); incorr=int(sub['_inn'].sum())
            hr.append({'三级部门':d3v,'四级部门':to_str(sub['四级部门'].iloc[0]),'五级部门':to_str(d5),'计数':cnt,'正确':corr,'不正确':incorr,'总计':corr+incorr,'_is_summary':False})
        if len(ge)>0:
            cnt=len(ge.drop_duplicates(subset=['工号']))
            corr=int(ge['_pn'].sum()); incorr=int(ge['_inn'].sum())
            hr.append({'三级部门':d3v,'四级部门':to_str(ge['四级部门'].iloc[0]),'五级部门':'/','计数':cnt,'正确':corr,'不正确':incorr,'总计':corr+incorr,'_is_summary':False})
        cnt=len(grp.drop_duplicates(subset=['工号']))
        corr=int(grp['_pn'].sum()); incorr=int(grp['_inn'].sum())
        hr.append({'三级部门':d3v,'四级部门':'','五级部门':'汇总','计数':cnt,'正确':corr,'不正确':incorr,'总计':corr+incorr,'_is_summary':True})
    hub_df=pd.DataFrame(hr)
    ws5=wb.create_sheet("hub排班是否正确"); _ws(ws5,[(1,'三级部门'),(2,'四级部门'),(3,'五级部门'),(4,'正确'),(5,'不正确'),(6,'总计'),(7,'正确率')],hub_df.to_dict('records'),rate_cols=[(7,'正确','总计')])
    wb.save(config['pivot_file'])
    print(f"透视分析完成: {config['pivot_file']}")

