def _be(r):
    return {'工号':to_str(r.get('工号','')),'姓名':to_str(r.get('姓名','')),'三级部门':to_str(r.get('三级部门','')),'四级部门':to_str(r.get('四级部门','')),'五级部门':to_str(r.get('五级部门','')),'班次名称':to_str(r.get('班次名称','')),'班次上班时间':to_str(r.get('班次上班时间','')),'班次下班时间':to_str(r.get('班次下班时间','')),'首打卡时间':to_str(r.get('首打卡时间','')),'末打卡时间':to_str(r.get('末打卡时间',''))}

def _boe(r):
    row=_be(r); row['超8H小时']=to_num(r.get('日超8H',0)); return row

def _bme(r):
    row=_be(r); row['缺卡数']=to_num(r.get('缺卡数',0)); row['班次内打卡次数']=to_num(r.get('班次内打卡次数',0)); row['标准打卡数']=to_num(r.get('标准打卡数',0)); return row

def _bce(r):
    row=_be(r); row['是否排班正确']=to_str(r.get('是否排班正确','')); return row

def _bse(r):
    row=_be(r); row['是否排班']=to_str(r.get('是否排班','')); return row

def dedupe(rows):
    seen=set(); return rows[rows['工号'].apply(lambda x: False if x in seen else (seen.add(x) or True))]

def summarize(group_df):
    unique = dedupe(group_df)
    total = len(unique)
    if total==0:
        return {'total':0,'all_employees':[],'日超8H':{'count':0,'total_hours':0,'rate':'0%','employees':[]},'排班':{'已排班':0,'未排班':0,'排班率':'0%','employees_未排班':[]},'排班正确':{'正确':0,'不正确':0,'不参与':0,'正确率':'0%','employees_不正确':[]},'打卡率':{'打卡率':'0%','打卡数':0,'标准打卡数':0,'缺卡数':0,'补签数_emp':0,'缺卡数_emp':0,'补签率':'0%','班次内打卡次数':0,'employees':[]},'HUB':{'total':0,'正确':0,'不正确':0,'正确率':'0%','employees_不正确':[]}}
    oe=unique[unique['是否日超8H']=='是']
    oc=len(oe); oh=round(unique['日超8H'].apply(to_num).sum(),2)
    ol=[_boe(r) for _,r in oe.iterrows()]
    sc=int((unique['是否排班']=='是').sum()); usc=total-sc
    sr=safe_div(sc,total)
    usl=[_bse(r) for _,r in unique[unique['是否排班']=='否'].iterrows()]
    cr=int((unique['是否排班正确']=='正确').sum()); icr=int((unique['是否排班正确']=='不正确').sum())
    npc=int((unique['是否排班正确']=='/').sum())
    crate=safe_div(cr,cr+icr)
    icl=[_bce(r) for _,r in unique[unique['是否排班正确']=='不正确'].iterrows()]
    ps=unique['班次内打卡次数'].apply(to_num).sum()
    stds=unique['标准打卡数'].apply(to_num).sum()
    ms=unique['缺卡数'].apply(to_num).sum()
    pr=safe_div(ps,stds)
    ea=unique.groupby('工号').agg(bq=('补签数','first'),qk=('缺卡数',lambda x:x.apply(to_num).sum()))
    bqs=ea['bq'].apply(to_num).sum(); qks=ea['qk'].sum()
    br=safe_div(bqs,bqs+qks)
    me=unique[unique['缺卡数'].apply(to_num)>0]
    ml=[_bme(r) for _,r in me.iterrows()]
    hm=unique['HUB']=='hub'
    ht=int(hm.sum()); hc=int(unique[hm]['是否排班正确'].apply(lambda x:1 if x=='正确' else 0).sum())
    hi=int(unique[hm]['是否排班正确'].apply(lambda x:1 if x=='不正确' else 0).sum())
    hr_=safe_div(hc,hc+hi)
    hil=[_bce(r) for _,r in unique[hm&(unique['是否排班正确']=='不正确')].iterrows()]
    return {'total':total,'all_employees':[_be(r) for _,r in unique.iterrows()],'日超8H':{'count':oc,'total_hours':oh,'rate':pct_str(safe_div(oc,total)),'employees':ol},'排班':{'已排班':sc,'未排班':usc,'排班率':pct_str(sr),'employees_未排班':usl},'排班正确':{'正确':cr,'不正确':icr,'不参与':npc,'正确率':pct_str(crate),'employees_不正确':icl},'打卡率':{'打卡率':pct_str(pr),'打卡数':round(ps,1),'标准打卡数':round(stds,1),'缺卡数':round(ms,1),'补签数_emp':round(bqs,1),'缺卡数_emp':round(qks,1),'补签率':pct_str(br),'班次内打卡次数':round(ps,1),'employees':ml},'HUB':{'total':ht,'正确':hc,'不正确':hi,'正确率':pct_str(hr_),'employees_不正确':hil}}

def run_report_data(config):
    df=pd.read_excel(config['metrics_file'], dtype=str)
    print(f"报告数据: {len(df)}行")
    dates=df['考勤日期'].dropna().unique()
    dr=f"{dates[0]} ~ {dates[-1]}" if len(dates)>1 else str(dates[0])
    ov=summarize(df)
    deps=[]
    for d3,grp in df.groupby('三级部门'):
        d3n=to_str(d3)
        if not d3n: continue
        d3s=summarize(grp)
        sds=[]
        gne=grp[grp['四级部门'].apply(lambda x:to_str(x)!='')]
        ge=grp[grp['四级部门'].apply(lambda x:to_str(x)=='')]
        for d4,sg in gne.groupby('四级部门'):
            sds.append({'name':to_str(d4),'summary':summarize(sg)})
        if len(ge)>0: sds.append({'name':'/','summary':summarize(ge)})
        sds.sort(key=lambda x:x['summary']['total'],reverse=True)
        deps.append({'name':d3n,'summary':d3s,'sub_depts':sds})
    deps.sort(key=lambda x:x['summary']['total'],reverse=True)
    rd={'meta':{'total_employees':ov['total'],'date_range':dr,'department_count':len(deps)},'overview':ov,'departments':deps}
    with open(config['report_json'],'w',encoding='utf-8') as f:
        json.dump(rd,f,ensure_ascii=False,indent=2)
    print(f"报告JSON: {config['report_json']} ({len(deps)}部门)")

