def run_render(config):
    """调用内置 render_report.py 生成 HTML 报告"""
    import base64 as b64
    RENDER_PY = b64.b64decode(_RENDER_REPORT_B64).decode('utf-8')
    with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False, encoding='utf-8') as f:
        f.write(RENDER_PY)
        tmp_path = f.name
    try:
        env = os.environ.copy()
        env['ATTENDANCE_WORKSPACE'] = config['workspace']
        env.pop('PYTHONPATH', None)
        print(f"调用 render_report.py (workspace={config['workspace']})")
        subprocess.run([sys.executable, tmp_path], env=env, check=True)
    finally:
        os.unlink(tmp_path)

# ============================================================
# 步骤5a: 同比对比计算 (对应 pipeline/steps/compute_comparison.py)
# ============================================================
REGIONS_MAP = {'FL':'FL 佛州大区','TX':'TX 德州大区','GL':'GL 大湖大区','WE':'WE 美西大区','MS':'MS 中南大区','NE':'NE 东北大区','Ground项目部':'Ground项目部'}

def compare(name, y, t, good_dir):
    if abs(y)<0.0001 and abs(t)<0.0001:
        return {'name':name,'yesterday':y,'today':t,'diff_pct':0,'diff_pp':0,'arrow':'→','color':'gray','text':'持平'}
    if abs(y)<0.0001:
        return {'name':name,'yesterday':y,'today':t,'diff_pct':None,'diff_pp':t*100,'arrow':'↑','color':'green' if good_dir=='up' else 'red','text':f'+{t*100:.1f}%'}
    diff=t-y; dp=diff/y*100; dpp=diff*100
    if abs(diff)<0.0001: arrow,color='→','gray'
    elif diff>0: arrow='↑'; color='green' if good_dir=='up' else 'red'
    else: arrow='↓'; color='red' if good_dir=='up' else 'green'
    sgn='+' if diff>0 else ''
    return {'name':name,'yesterday':y,'today':t,'diff_pct':dp,'diff_pp':dpp,'arrow':arrow,'color':color,'text':f'{sgn}{dpp:.1f}%'}

def run_comparison(config, prev_workspace):
    xp=os.path.join(prev_workspace,'透视分析.xlsx')
    if not os.path.exists(xp): print(f"错误: 找不到 {xp}"); return
    yesterday={}
    for sn in ['日超8H','是否排班','是否排班正确','打卡率','hub排班是否正确']:
        try: dy=pd.read_excel(xp,sheet_name=sn)
        except:
            if sn=='打卡率':
                try: dy=pd.read_excel(xp,sheet_name='缺卡'); print("兼容旧版'缺卡'Sheet")
                except: continue
            else: continue
        sums=dy[dy['四级部门']=='汇总']
        if sn=='日超8H': yesterday['__overview__超标率']=float(sums['超过人数'].sum()/sums['总计人数'].sum())
        elif sn=='是否排班':
            ts=int(sums['已排班数'].sum()); te=int(sums['总计人数'].sum())
            yesterday['__overview__排班率']=ts/te if te>0 else 0
        elif sn=='是否排班正确':
            tc=int(sums['正确数量'].sum()); ti=int(sums['不正确数量'].sum()); tt=tc+ti
            yesterday['__overview__正确率']=tc/tt if tt>0 else 0
        elif sn=='打卡率' or sn=='缺卡':
            if '打卡数' in dy.columns:
                tp=int(sums['打卡数'].sum()); tst=int(sums['标准打卡数量'].sum())
            else:
                tm=int(sums['缺卡数量'].sum()); tst=int(sums['标准打卡数量'].sum()); tp=tst-tm
            yesterday['__overview__打卡率']=tp/tst if tst>0 else 0
        elif sn=='hub排班是否正确': yesterday['__overview__hub正确率']=float(dy['正确'].sum()/(dy['正确'].sum()+dy['不正确'].sum()))
        for rk,rn in REGIONS_MAP.items():
            if rk not in yesterday: yesterday[rk]={}
            row=dy[dy['三级部门']==rn]
            if len(row)==0: continue
            if sn=='hub排班是否正确':
                sm=row[row['四级部门'].isna()|(row['四级部门']=='汇总')]
                if len(sm)==0: sm=row.iloc[-1:]
                s=sm.iloc[0]; yesterday[rk]['hub正确率']=float(s['正确率']) if pd.notna(s['正确率']) else 0; continue
            sm=row[row['四级部门']=='汇总']
            if len(sm)==0: continue
            s=sm.iloc[0]
            if sn=='日超8H': yesterday[rk]['超标率']=float(s['超过人数']/s['总计人数']) if s['总计人数']>0 else 0
            elif sn=='是否排班': yesterday[rk]['排班率']=float(s['排班率'])
            elif sn=='是否排班正确': yesterday[rk]['正确率']=float(s['正确率'])
            elif sn=='打卡率' or sn=='缺卡': yesterday[rk]['打卡率']=float(s['打卡率']) if '打卡率' in s.index else (1-float(s['缺卡率']) if '缺卡率' in s.index else 0)

    with open(config['report_json'],'r',encoding='utf-8') as f: rp=json.load(f)
    ov=rp.get('overview',{})
    o8=ov.get('日超8H',{}); pb=ov.get('排班',{}); pbc=ov.get('排班正确',{}); qk=ov.get('打卡率',{}); hub=ov.get('HUB',{})
    today={}
    today['__overview__超标率']=float(o8.get('rate','0%').rstrip('%'))/100
    today['__overview__排班率']=float(pb.get('排班率','0%').rstrip('%'))/100
    today['__overview__正确率']=float(pbc.get('正确率','0%').rstrip('%'))/100
    today['__overview__打卡率']=float(qk.get('打卡率','0%').rstrip('%'))/100
    today['__overview__hub正确率']=float(hub.get('正确率','0%').rstrip('%'))/100
    deps=rp.get('departments',[])
    for dep in deps:
        name=dep.get('name','')
        if name not in REGIONS_MAP.values(): continue
        rk=None
        for k,v in REGIONS_MAP.items():
            if v==name: rk=k; break
        if rk is None: continue
        sds=dep.get('sub_depts',[])
        te=0; exc=0; sc=0; us=0; co=0; inc=0; pt=0; stt=0
        for sd in sds:
            s=sd.get('summary',{})
            te+=s.get('total',0); exc+=s.get('日超8H',{}).get('count',0)
            sc+=s.get('排班',{}).get('已排班',0); us+=s.get('排班',{}).get('未排班',0)
            co+=s.get('排班正确',{}).get('正确',0); inc+=s.get('排班正确',{}).get('不正确',0)
            pt+=int(s.get('打卡率',{}).get('打卡数',0)); stt+=int(s.get('打卡率',{}).get('标准打卡数',0))
        today[rk]={'超标率':exc/te if te>0 else 0,'排班率':sc/(sc+us) if(sc+us)>0 else 0,'正确率':co/(co+inc) if(co+inc)>0 else 0,'打卡率':pt/stt if stt>0 else 0}

    results={}
    ovm=[('超标率','down'),('排班率','up'),('正确率','up'),('打卡率','up'),('HUB正确率','up')]
    ovk=['__overview__超标率','__overview__排班率','__overview__正确率','__overview__打卡率','__overview__hub正确率']
    results['__overview__']={}
    for i,(nm,dr) in enumerate(ovm):
        k=ovk[i]
        if k in yesterday and k in today: results['__overview__'][nm]=compare(nm,yesterday[k],today[k],dr)
    for rk in ['FL','TX','GL','WE','MS','NE','Ground项目部']:
        yd=yesterday.get(rk,{}); td=today.get(rk,{}); rr={}
        for nm,dr in [('超标率','down'),('排班率','up'),('正确率','up'),('打卡率','up')]:
            if nm in yd and nm in td: rr[nm]=compare(nm,yd[nm],td[nm],dr)
        if 'hub正确率' in yd:
            ht=today.get('__overview__hub正确率',yd['hub正确率'])
            rr['HUB正确率']=compare('HUB正确率',yd['hub正确率'],ht,'up')
        results[rk]=rr
    with open(config['comparison_json'],'w',encoding='utf-8') as f: json.dump(results,f,ensure_ascii=False,indent=2)
    print(f"对比完成: {config['comparison_json']}")

# ============================================================
# 步骤5b: 同比变化注入 (对应 pipeline/steps/inject_comparison.py)
# ============================================================
def _build_injected_html(html, overview_cmp=None, region_cmp=None):
    html = re.sub(r'/\* ===== 同比变化标识样式 ===== \*/\s*\.cmp-badge[^}]*}[^}]*}[^}]*}[^}]*}','',html,flags=re.DOTALL)
    html = re.sub(r'\n\s*/\* ===== 同比变化标识样式 ===== \*/[\s\S]*?(?=\n\s*/\*|\n</style>)','',html)
    html = re.sub(r'<script>\s*// ===== 同比变化标识 \(自动注入\) =====[\s\S]*?</script>','',html)
    html = re.sub(r'\n{3,}','\n\n',html)
    cmp_css='\n/* ===== 同比变化标识样式 ===== */\n.cmp-badge{display:inline;vertical-align:middle}\n.cmp-badge-green{color:#22c55e}\n.cmp-badge-red{color:#ef4444}\n.cmp-badge-gray{color:#64748b}\n'
    if '/* ===== 同比变化标识样式 ===== */' not in html:
        idx=html.find('</style>')
        if idx>0: html=html[:idx]+cmp_css+html[idx:]
    parts=['<script>','// ===== 同比变化标识 (自动注入) =====']
    if overview_cmp: parts.append('var CMP_OVERVIEW = '+json.dumps(overview_cmp,ensure_ascii=False)+';')
    if region_cmp: parts.append('var CMP_REGION = '+json.dumps(region_cmp,ensure_ascii=False)+';')
    parts.append("(function(){function addBadges(){var cmpData=window.CMP_OVERVIEW||window.CMP_REGION||{};var cards=document.querySelectorAll('.card,.kpi-card');cards.forEach(function(card){var titleEl=card.querySelector('.card-title,.kpi-label');if(!titleEl)return;var title=titleEl.textContent.trim();var existing=card.querySelector('.cmp-badge');if(existing)existing.remove();var key=null;if(title.includes('日超8H')||title.includes('超标')){key='超标率'}else if(title.includes('排班率')&&!title.includes('正确')&&!title.includes('HUB')){key='排班率'}else if(title.includes('排班正确率')||(title.includes('正确率')&&!title.includes('HUB'))){key='正确率'}else if(title.includes('打卡率')){key='打卡率'}else if(title.includes('HUB排班正确率')||title.includes('HUB正确率')){key='HUB正确率'}if(!key||!cmpData[key])return;var c=cmpData[key];var diffPp=c.diff_pp;var ppText=diffPp!==0?(diffPp>0?'+':'')+diffPp.toFixed(1)+'%':'持平';var clr=c.color==='green'?'#22c55e':(c.color==='red'?'#ef4444':'#64748b');var badge=document.createElement('span');badge.className='cmp-badge';badge.style.cssText='color:'+clr+';font-size:11px;margin-left:6px;white-space:nowrap;font-weight:600';badge.textContent=c.arrow+' '+ppText;var valueEl=card.querySelector('.card-value,.kpi-value');if(valueEl){valueEl.appendChild(badge)}else{titleEl.appendChild(badge)}})}addBadges();setTimeout(addBadges,500);setTimeout(addBadges,1500);setTimeout(addBadges,3000);var observer=new MutationObserver(function(){setTimeout(addBadges,300)});var mainContent=document.getElementById('mainContent');if(mainContent)observer.observe(mainContent,{childList:true,subtree:true})})();</script>")
    compare_js='\n'.join(parts)
    html=html.replace('</body>',compare_js+'\n</body>',1)
    return html

def run_inject(config):
    cp=config['comparison_json']
    if not os.path.exists(cp): print(f"错误: 找不到 {cp}"); return
    with open(cp,'r',encoding='utf-8') as f: cmp=json.load(f)
    oc=cmp.get('__overview__',{})
    ws=config['workspace']
    for fname,rc in [('考勤首页.html',(oc,None)),('考勤分析报告.html',(oc,None))]:
        fp=os.path.join(ws,fname)
        if os.path.exists(fp):
            with open(fp,'r',encoding='utf-8') as f: html=f.read()
            html=_build_injected_html(html,overview_cmp=rc[0],region_cmp=rc[1])
            with open(fp,'w',encoding='utf-8') as f: f.write(html)
            print(f'Updated: {fname}')
    rfs={'WE':'考勤分析_WE 美西大区.html','NE':'考勤分析_NE 东北大区.html','FL':'考勤分析_FL 佛州大区.html','TX':'考勤分析_TX 德州大区.html','Ground项目部':'考勤分析_Ground项目部.html','MS':'考勤分析_MS 中南大区.html','GL':'考勤分析_GL 大湖大区.html'}
    for rk,fn in rfs.items():
        fp=os.path.join(ws,fn)
        if os.path.exists(fp):
            with open(fp,'r',encoding='utf-8') as f: html=f.read()
            html=_build_injected_html(html,region_cmp=cmp.get(rk,{}))
            with open(fp,'w',encoding='utf-8') as f: f.write(html)
            print(f'Updated: {fn}')
    print('同比变化注入完成!')

# ============================================================
# CLI 入口 (对应 main.py)
# ============================================================
STEPS = [
    ('clean',     run_clean,      '步骤1: 数据清洗'),
    ('metrics',   run_metrics,    '步骤2: 指标计算'),
    ('pivot',     run_pivot,      '步骤3: 透视分析'),
    ('report',    run_report_data,'步骤4a: 构建报告JSON'),
    ('render',    run_render,     '步骤4b: 生成HTML报告'),
    ('compare',   run_comparison, '步骤5a: 同比对比计算'),
    ('inject',    run_inject,     '步骤5b: 注入同比变化标识'),
]
STEP_FUNCS = {s[0]:s[1] for s in STEPS}

def main():
    parser = argparse.ArgumentParser(description='考勤排班数据分析全流程',formatter_class=argparse.RawDescriptionHelpFormatter)
    parser.add_argument('--workspace',default=None,help='工作目录(默认当前目录)')
    parser.add_argument('--prev-workspace',default=None,help='前次工作目录(同比对比用)')
    parser.add_argument('--roster-index',type=int,default=12,help='花名册文件序号(默认12)')
    subparsers=parser.add_subparsers(dest='step',help='执行指定步骤')
    for name,_,desc in STEPS: subparsers.add_parser(name,help=desc)
    subparsers.add_parser('all',help='完整流程(步骤1-4b)')
    subparsers.add_parser('all-with-compare',help='完整流程含同比(步骤1-5b)')
    subparsers.add_parser('quick-report',help='快速报告(步骤4a-4b)')
    args=parser.parse_args()
    if not args.step: parser.print_help(); return
    input_dir = args.workspace if args.workspace else None
    config = get_config(args.workspace, input_dir=input_dir)
    print(f"工作目录: {config['workspace']}")
    if args.step=='all':
        for name,func,_ in STEPS[:5]:
            print(f'\n{"="*60}\n>>> {name}\n{"="*60}')
            kwargs={}
            if name=='clean': kwargs['roster_index']=args.roster_index
            func(config,**kwargs)
    elif args.step=='all-with-compare':
        for name,func,_ in STEPS:
            print(f'\n{"="*60}\n>>> {name}\n{"="*60}')
            kwargs={}
            if name=='clean': kwargs['roster_index']=args.roster_index
            elif name=='compare':
                if not args.prev_workspace: print("跳过: 未提供--prev-workspace"); continue
                kwargs['prev_workspace']=args.prev_workspace
            func(config,**kwargs)
    elif args.step=='quick-report':
        for name,func,_ in STEPS[3:5]:
            print(f'\n{"="*60}\n>>> {name}\n{"="*60}'); func(config)
    else:
        func=STEP_FUNCS.get(args.step)
        if func:
            kwargs={}
            if args.step=='clean': kwargs['roster_index']=args.roster_index
            elif args.step=='compare':
                if not args.prev_workspace: print("错误: --prev-workspace必须"); return
                kwargs['prev_workspace']=args.prev_workspace
            func(config,**kwargs)

if __name__=='__main__':
    main()

